import{_ as l,c as t,a as o,o as i}from"./app-CEcM0piI.js";const c={};function d(a,e){return i(),t("div",null,e[0]||(e[0]=[o('<p>!important &gt; 行内样式 &gt; id选择器 &gt; 类选择器、属性选择器、伪类选择器 &gt; 标签选择器、伪元素选择器</p><p>选择器权重相同时，后声明的样式会覆盖前面的样式 继承的样式不受优先级的影响，其权重值为0</p><h1 id="css中的垂直水平居中有哪些方法" tabindex="-1"><a class="header-anchor" href="#css中的垂直水平居中有哪些方法"><span>CSS中的垂直水平居中有哪些方法</span></a></h1><ul><li><p><strong>Flex布局</strong></p><ul><li>父元素设置<code>display: flex;</code>。</li><li>水平居中：<code>justify-content: center;</code>。</li><li>垂直居中：<code>align-items: center;</code>。</li></ul></li><li><p><strong>定位+transform</strong></p><ul><li>子元素绝对定位：<code>position: absolute; top: 50%; left: 50%;</code>。</li><li>使用<code>transform: translate(-50%, -50%);</code>进行偏移。</li></ul></li><li><p><strong>Flex+auto</strong></p><ul><li>父元素设置<code>display: flex;</code>。</li><li>子元素设置<code>margin: auto;</code>，利用auto margin实现居中。</li></ul></li></ul><h1 id="行内元素和块级元素分别有哪些" tabindex="-1"><a class="header-anchor" href="#行内元素和块级元素分别有哪些"><span>行内元素和块级元素分别有哪些</span></a></h1><h3 id="行内元素-inline-elements" tabindex="-1"><a class="header-anchor" href="#行内元素-inline-elements"><span>行内元素（Inline Elements）</span></a></h3><p>行内元素不会在前后开始新的一行，并且只占自己所需宽度。它们通常用于包裹或者标记文本中的某些部分：</p><ul><li><code>&lt;a&gt;</code>：定义超链接。</li><li><code>&lt;span&gt;</code>：无语义的容器标签，常用于应用样式或JavaScript操作。</li><li><code>&lt;strong&gt;</code> 和 <code>&lt;b&gt;</code>：加粗显示文本，前者带有强调含义，后者仅改变外观。</li><li><code>&lt;em&gt;</code> 和 <code>&lt;i&gt;</code>：斜体显示文本，前者用于强调，后者用于技术性或非语言目的。</li><li><code>&lt;img&gt;</code>：插入图像。</li><li><code>&lt;input&gt;</code>：创建交互控件以接受用户输入。</li><li><code>&lt;label&gt;</code>：为表单控件定义标注。</li><li><code>&lt;button&gt;</code>：可点击的按钮。</li><li><code>&lt;textarea&gt;</code>：多行文本输入框。</li><li><code>&lt;select&gt;</code>：下拉列表选择框。</li></ul><h3 id="块级元素-block-level-elements" tabindex="-1"><a class="header-anchor" href="#块级元素-block-level-elements"><span>块级元素（Block-Level Elements）</span></a></h3><p>块级元素会在新行上开始，并且会尽可能地扩展其宽度来填充父容器的宽度。它们通常用于构建网站的结构：</p><ul><li><code>&lt;div&gt;</code>：无语义的容器标签，常用于布局。</li><li><code>&lt;h1&gt;</code> 到 <code>&lt;h6&gt;</code>：标题标签，其中<code>&lt;h1&gt;</code>是最高级别的标题，重要性依次递减。</li><li><code>&lt;p&gt;</code>：定义段落。</li><li><code>&lt;form&gt;</code>：包含交互控件的表单。</li><li><code>&lt;header&gt;</code>：定义文档或节的页眉。</li><li><code>&lt;footer&gt;</code>：定义文档或节的页脚。</li><li><code>&lt;nav&gt;</code>：定义导航链接的部分。</li><li><code>&lt;article&gt;</code>：定义文章内容。</li><li><code>&lt;section&gt;</code>：定义文档中的节。</li><li><code>&lt;aside&gt;</code>：定义页面内容之外的内容，比如侧边栏。</li><li><code>&lt;table&gt;</code>：表格数据。</li><li><code>&lt;ul&gt;</code>, <code>&lt;ol&gt;</code>, <code>&lt;li&gt;</code>：无序列表、有序列表及其列表项。</li></ul><p>CSS提供了<code>display</code>属性，允许你改变元素的默认显示类型。例如，使用<code>display: inline;</code>可以使块级元素表现得像行内元素，而使用<code>display: block;</code>可以让行内元素表现得像块级元素。</p>',12)]))}const s=l(c,[["render",d]]),r=JSON.parse('{"path":"/front/interview/7/","title":"7 css","lang":"zh-CN","frontmatter":{"title":"7 css","createTime":"2025/06/16 10:08:16","permalink":"/front/interview/7/"},"readingTime":{"minutes":2.09,"words":626},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/面经/7 css.md","headers":[]}');export{s as comp,r as data};
